// --- MIRON WIDGET SPLIT LOGIC ---
win.insertMironWidget = () => {
    if (!win.lastHighlightedRange) return false;

    const range = win.lastHighlightedRange;
    const startNode = range.startContainer;
    let page = startNode.parentElement.closest('.page');
    if (!page) page = doc.body; 

    const textContainer = page.querySelector('.text-container') || page;

    if (page.dataset.hasSplit === "true") {
        console.log("Page already split");
        return false;
    }

    const GAP_HEIGHT = 350; 
    const rect = range.getBoundingClientRect();
    const pageRect = page.getBoundingClientRect();

    // Calculate split dynamically
    let SPLIT_Y = pageRect.bottom - rect.bottom;
    SPLIT_Y -= 20; // Padding

    const currentH = parseInt(page.style.height || page.getAttribute('height') || pageRect.height);
    page.style.height = (currentH + GAP_HEIGHT) + "px";

    const spans = textContainer.querySelectorAll('span, p, div');
    let movedCount = 0;

    spans.forEach(span => {
        if (span.classList.contains('in-book-widget')) return;

        const bottomVal = parseInt(span.style.bottom);
        if (!isNaN(bottomVal)) {
            if (bottomVal > SPLIT_Y) {
                span.classList.add('shifting-text');
                span.style.bottom = (bottomVal + GAP_HEIGHT) + "px";
                movedCount++;
            }
        } else {
            const topVal = parseInt(span.style.top);
            const splitTop = pageRect.height - SPLIT_Y;
            if (!isNaN(topVal) && topVal > splitTop) {
                span.classList.add('shifting-text');
                span.style.top = (topVal + GAP_HEIGHT) + "px";
                movedCount++;
            }
        }
    });

    const widget = doc.createElement('div');
    widget.className = 'in-book-widget';
    widget.style.height = GAP_HEIGHT + 'px';

    if (win.getComputedStyle(page).position === 'static') {
        page.style.position = 'relative';
    }

    widget.style.bottom = SPLIT_Y + 'px'; 

    const snippet = range.toString().substring(0, 40);

    widget.innerHTML = `
        <div class="miron-widget-content">
            <div class="miron-widget-header">
                <i class="fa-solid fa-wand-magic-sparkles"></i> Miron Insight
            </div>
            <p class="miron-widget-text">Analyzing: <strong>"${snippet}..."</strong></p>
            <p class="miron-widget-sub">I've parsed this section. Would you like me to break down this concept visually or generate a quick practice question?</p>
            <div class="miron-widget-actions">
                <button class="miron-widget-btn primary">Explain Concept</button>
                <button class="miron-widget-btn">Generate Quiz</button>
            </div>
        </div>
    `;

    textContainer.appendChild(widget);
    page.dataset.hasSplit = "true";
    win.CSS.highlights.clear();

    // Sync the new height with the Reader Physics Engine
    setTimeout(() => {
        if (win.updateParentDims) win.updateParentDims();
    }, 100);

    return true;
};

