 667 |                                 if (sentenceEndRegex.test(text[i])) {
 668 |                                     finalStartNode = prevNode;
 669 |                                     finalStartOffset = i + 1;
 670 |                                     if(text[finalStartOffset] === ' ') finalStartOffset++;
