 627 |                 function findSentenceRange(rootDoc, startNode, startOffset) {
 628 |                     const sentenceEndRegex = /[.!?]/;
 629 |                     
 630 |                     // Helper: TreeWalker for linear text traversal
 631 |                     function createWalker(root) {
 632 |                         return rootDoc.createTreeWalker(root, NodeFilter.SHOW_TEXT, null, false);
 633 |                     }
 634 | 
 635 |                     // 1. BACKWARD SCAN (Find start)
 636 |                     let currentStartNode = startNode;
 637 |                     let currentStartOffset = startOffset;
 638 |                     let finalStartNode = startNode;
 639 |                     let finalStartOffset = 0;
 640 | 
 641 |                     // Check backwards inside the clicked node first
 642 |                     let textBefore = currentStartNode.textContent.substring(0, currentStartOffset);
 643 |                     let lastPuncIndex = -1;
 644 |                     
 645 |                     for(let i = textBefore.length - 1; i >= 0; i--) {
 646 |                         if(sentenceEndRegex.test(textBefore[i])) {
 647 |                             lastPuncIndex = i;
 648 |                             break;
 649 |                         }
 650 |                     }
 651 | 
 652 |                     if (lastPuncIndex !== -1) {
 653 |                         finalStartOffset = lastPuncIndex + 1;
 654 |                         // Skip space if present right after dot
 655 |                         if(currentStartNode.textContent[finalStartOffset] === ' ') finalStartOffset++;
 656 |                     } else {
 657 |                         // Walk backwards through DOM
 658 |                         const walker = createWalker(docBody);
 659 |                         walker.currentNode = currentStartNode;
 660 |                         let prevNode = walker.previousNode();
 661 |                         let foundStart = false;
 662 | 
 663 |                         while (prevNode && !foundStart) {
 664 |                             const text = prevNode.textContent;
 665 |                             for (let i = text.length - 1; i >= 0; i--) {
 666 |                                 if (sentenceEndRegex.test(text[i])) {
 667 |                                     finalStartNode = prevNode;
 668 |                                     finalStartOffset = i + 1;
 669 |                                     if(text[finalStartOffset] === ' ') finalStartOffset++;
 670 |                                     foundStart = true;
 671 |                                     break;
 672 |                                 }
 673 |                             }
 674 |                             if (!foundStart) {
 675 |                                 finalStartNode = prevNode;
 676 |                                 finalStartOffset = 0;
 677 |                                 prevNode = walker.previousNode();
 678 |                             }
 679 |                         }
 680 |                     }
 681 | 
 682 |                     // 2. FORWARD SCAN (Find end)
 683 |                     let currentEndNode = startNode;
 684 |                     let currentEndOffset = startOffset;
 685 |                     let finalEndNode = startNode;
 686 |                     let finalEndOffset = startNode.textContent.length;
 687 | 
 688 |                     let textAfter = currentEndNode.textContent.substring(currentEndOffset);
 689 |                     let nextPuncIndex = textAfter.search(sentenceEndRegex);
 690 | 
 691 |                     if (nextPuncIndex !== -1) {
 692 |                         finalEndOffset = currentEndOffset + nextPuncIndex + 1;
 693 |                     } else {
 694 |                         // Walk forwards through DOM
 695 |                         const walker = createWalker(docBody);
 696 |                         walker.currentNode = currentEndNode;
 697 |                         let nextNode = walker.nextNode();
 698 |                         let foundEnd = false;
 699 | 
 700 |                         while (nextNode && !foundEnd) {
 701 |                             const text = nextNode.textContent;
 702 |                             const puncIdx = text.search(sentenceEndRegex);
 703 |                             if (puncIdx !== -1) {
 704 |                                 finalEndNode = nextNode;
 705 |                                 finalEndOffset = puncIdx + 1;
 706 |                                 foundEnd = true;
 707 |                             } else {
 708 |                                 finalEndNode = nextNode;
 709 |                                 finalEndOffset = text.length;
 710 |                                 nextNode = walker.nextNode();
 711 |                             }
 712 |                         }
 713 |                     }
 714 | 
 715 |                     // Create the final Range
 716 |                     const r = rootDoc.createRange();
 717 |                     try {
 718 |                         r.setStart(finalStartNode, finalStartOffset);
 719 |                         r.setEnd(finalEndNode, finalEndOffset);
 720 |                         return r;
 721 |                     } catch (e) {
 722 |                         console.warn("Sentence Range Error:", e);
 723 |                         return null;
 724 |                     }
 725 |                 }
 726 |             } catch (err) {
 727 |                 console.error("Iframe Load Error:", err);
 728 |             }
 729 |         }, 100);
 730 |     };
