 775 |         } else {
 776 |             if (s.x > 0) { s.x = 0; v.x = 0; }
 777 |             if (s.x < vw - visualW) { s.x = vw - visualW; v.x = 0; }
 778 |         }
 779 | 
 780 |         // Y Constraint
 781 |         if (visualH < vh) {
 782 |             s.y = (vh - visualH) / 2;
 783 |             v.y = 0;
 784 |         } else {
 785 |             if (s.y > 0) { s.y = 0; v.y = 0; }
