win.insertMironWidget = () => {
    if (!win.lastHighlightedRange) return false;

    const GAP = 280; // Total vertical space created
    const range = win.lastHighlightedRange;
    const rect = range.getBoundingClientRect();

    const page = range.startContainer.parentElement.closest('.page');
    if (!page) return;
    const container = page.querySelector('.text-container');
    const containerRect = container.getBoundingClientRect();

    // 1. Calculate local selection bottom (relative to container bottom)
    // This works because PDF text uses 'bottom: ...px' coordinate system
    const selectionBottomLocal = containerRect.bottom - rect.bottom;

    // 2. Clear existing widget
    if (doc.querySelector('.in-book-widget')) win.closeMironWidget();

    // 3. Shift every element physically below the selection
    const elements = container.querySelectorAll('span, div, img');
    elements.forEach(el => {
        if (el.classList.contains('in-book-widget')) return;

        const currentBottom = parseFloat(el.style.bottom);
        if (!isNaN(currentBottom) && currentBottom < selectionBottomLocal + 5) {
            // Store original position to allow recovery
            if (!el.dataset.orgBottom) el.dataset.orgBottom = el.style.bottom;
            el.style.bottom = (currentBottom - GAP) + "px";
        }
    });

    // 4. Expand the page canvas height
    const orgHeight = parseFloat(page.style.height);
    if (!page.dataset.orgHeight) page.dataset.orgHeight = page.style.height;
    page.style.height = (orgHeight + GAP) + "px";

    // 5. Create and Position the Widget
    const widget = doc.createElement('div');
    widget.className = 'in-book-widget';
    // Positioned exactly where the text was pushed down
    const widgetTop = (rect.bottom - containerRect.top) + 20;
    widget.style.top = widgetTop + "px";

    widget.innerHTML = `
        <div class="miron-widget-content">
            <div class="miron-widget-header">
                <i class="fa-solid fa-wand-magic-sparkles"></i> Miron Insight
            </div>
            <div class="miron-widget-quote">"${range.toString().substring(0, 60)}..."</div>
            <div class="miron-widget-actions">
                <button class="miron-widget-btn primary">Explain</button>
                <button class="miron-widget-btn secondary" onclick="window.closeMironWidget()">Dismiss</button>
            </div>
        </div>
    `;

    container.appendChild(widget);

    // 6. Finalize
    win.CSS.highlights.clear();
    requestAnimationFrame(() => {
        widget.classList.add('active');
        if (win.updateParentDims) win.updateParentDims();
    });

    return true;
};

